import{_ as i,H as a,f as l,i as e}from"./chunks/framework.eFU6Tutu.js";const r="/assets/mint_mohito.oontDuFE.jpg",d="/assets/mint_meat.BFAgvPmk.jpg",h="/assets/mint_icecream.BG70ZFpV.jpg",o="/assets/mint_jam.CrCuoHLU.jpg",q=JSON.parse('{"title":"Готовые идеи рецептов с мятой","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/mint.md","filePath":"recipes/mint.md"}'),s={name:"recipes/mint.md"};function n(c,t,p,m,b,u){return a(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="готовые-идеи-рецептов-с-мятои" tabindex="-1">Готовые идеи рецептов с мятой <a class="header-anchor" href="#готовые-идеи-рецептов-с-мятои" aria-label="Permalink to &quot;Готовые идеи рецептов с мятой&quot;">​</a></h1><h2 id="мохито-безалкогольныи" tabindex="-1">Мохито (безалкогольный) <a class="header-anchor" href="#мохито-безалкогольныи" aria-label="Permalink to &quot;Мохито (безалкогольный)&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-3-порции" tabindex="-1">Ингредиенты (на 3 порции) <a class="header-anchor" href="#ингредиенты-на-3-порции" aria-label="Permalink to &quot;Ингредиенты (на 3 порции)&quot;">​</a></h3><ul><li>Газировка (Спрайт) — 600 мл</li><li>Мята — 10 листьев</li><li>Лайм — 1 шт</li><li>Лимон — 0.5 шт</li><li>Сахар — 1 ст. ложка</li><li>Лёд — по вкусу</li></ul></div><div><p><img src="'+r+'" alt="Мохито"></p></div></div><h3 id="калорииность-состава-в-однои-порции-300г" tabindex="-1">Калорийность состава в одной порции (300г) <a class="header-anchor" href="#калорииность-состава-в-однои-порции-300г" aria-label="Permalink to &quot;Калорийность состава в одной порции (300г)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>0 г</td><td>0 г</td><td>0 г</td><td>128</td></tr></tbody></table><h3 id="приготовление" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 25 мин</p><ol><li>Лайм и лимон вымойте и обсушите</li><li>Нарежьте цитрусы тонкими полукружьями</li><li>Добавьте сахар и листья мяты</li><li>Разомните вилкой или ложкой</li><li>Разложите смесь по бокалам</li><li>Часть льда переложите в чашу блендера. Взбейте его до состояния крупной крошки</li><li>Добавьте ледяную крошку (около 0,75 объема бокала) и целые кубики льда в напиток</li><li>Напиток украсьте целыми кружочками лайма и листиками мяты. Пейте сразу же после приготовления</li></ol><h2 id="мясо-по-чешски" tabindex="-1">Мясо по чешски <a class="header-anchor" href="#мясо-по-чешски" aria-label="Permalink to &quot;Мясо по чешски&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-4-порции" tabindex="-1">Ингредиенты (на 4 порции) <a class="header-anchor" href="#ингредиенты-на-4-порции" aria-label="Permalink to &quot;Ингредиенты (на 4 порции)&quot;">​</a></h3><ul><li>Куриное филе - 600 гр</li><li>Фета - 30 гр</li><li>Оливковое масло - 20 мл</li><li>Мята - 40 гр</li><li>Лимонный сок - 20 мл</li><li>Соль, перец - по вкусу</li></ul></div><div><p><img src="'+d+'" alt="Мясо по чешски"></p></div></div><h3 id="калорииность-состава-в-однои-порции-300г-1" tabindex="-1">Калорийность состава в одной порции (300г) <a class="header-anchor" href="#калорииность-состава-в-однои-порции-300г-1" aria-label="Permalink to &quot;Калорийность состава в одной порции (300г)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>21 г</td><td>5 г</td><td>1 г</td><td>137</td></tr></tbody></table><h3 id="приготовление-1" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-1" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 1 ч 15 мин</p><ol><li>В каждом куске филе сделайте надрез-карман.</li><li>Нафаршируйте кусочками феты и листьями мяты (5-6 шт на порцию).</li><li>Замаринуйте в оливковом масле, лимонном соке, соли и перце — 30 минут.</li><li>Обжарьте на сковороде по 2 минуты с каждой стороны до корочки.</li><li>Доведите до готовности в духовке при 150-160°C — 4-5 минут.</li></ol><h2 id="мороженое-с-мятои-и-шоколадом" tabindex="-1">Мороженое с мятой и шоколадом <a class="header-anchor" href="#мороженое-с-мятои-и-шоколадом" aria-label="Permalink to &quot;Мороженое с мятой и шоколадом&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;"><div><p><strong>Ингредиенты (на 6 порций):</strong></p><ul><li>Молоко — 300 мл</li><li>Сливки (15%) — 500 мл</li><li>Мята — 150 г</li><li>Сахарная пудра — 50 г</li><li>Шоколад — 50 г</li></ul><h3 id="калорииность-на-100г" tabindex="-1">Калорийность на 100г <a class="header-anchor" href="#калорииность-на-100г" aria-label="Permalink to &quot;Калорийность на 100г&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>3 г</td><td>12 г</td><td>12 г</td><td>213</td></tr></tbody></table></div><div><p><img src="'+h+'" alt="Мятное мороженое с шоколадом"></p></div></div><h3 id="приготовление-8-ч" tabindex="-1">Приготовление (8 ч) <a class="header-anchor" href="#приготовление-8-ч" aria-label="Permalink to &quot;Приготовление (8 ч)&quot;">​</a></h3><ol><li>Налейте молоко и сливки в кастрюлю.</li><li>Добавьте мяту, доведите до кипения, снимите с огня и настаивайте 1 час.</li><li>Процедите через сито, хорошо отожмите мяту.</li><li>Добавьте сахарную пудру, перемешайте.</li><li>Вылейте в контейнер и поставьте в морозилку.</li><li><strong>Важно!</strong> Каждые 1.5–2 часа перемешивайте массу (всего не менее 3 раз). Лучше использовать погружной блендер — иначе получится лёд, а не воздушное мороженое.</li><li>Добавьте кусочки шоколада, перемешайте в 4-й раз и снова в морозилку.</li><li>Перед подачей достаньте мороженое из морозилки и подержите 10–15 минут при комнатной температуре.</li></ol><h2 id="мятное-варенье" tabindex="-1">Мятное варенье <a class="header-anchor" href="#мятное-варенье" aria-label="Permalink to &quot;Мятное варенье&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;"><div><p><strong>Ингредиенты (на 20 порций):</strong></p><ul><li>Мята — 500 г</li><li>Сахар — 2 кг</li><li>Лимоны — 1 шт.</li><li>Вода — 1 л</li></ul><h3 id="калорииность-на-100г-1" tabindex="-1">Калорийность на 100г <a class="header-anchor" href="#калорииность-на-100г-1" aria-label="Permalink to &quot;Калорийность на 100г&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>1 г</td><td>0 г</td><td>56 г</td><td>227</td></tr></tbody></table></div><div><p><img src="'+o+'" alt="Мятное варенье"></p></div></div><h3 id="приготовление-19-ч" tabindex="-1">Приготовление (19 ч) <a class="header-anchor" href="#приготовление-19-ч" aria-label="Permalink to &quot;Приготовление (19 ч)&quot;">​</a></h3><ol><li>Переберите мяту: отделите листья от веточек. Листья уберите в холодильник, веточки не выбрасывайте.</li><li>Сварите сироп: вода + 1 кг сахара + веточки мяты. Доведите до кипения, варите 5 минут. Настаивайте 6 часов.</li><li>Процедите сироп, добавьте второй килограмм сахара и нарезанный кружочками лимон (вместе с кожурой). Доведите до кипения, варите 5 минут.</li><li>Добавьте свежие листья мяты из холодильника, перемешайте. Доведите до кипения и оставьте настаиваться на ночь под крышкой.</li><li>Утром процедите сироп (отожмите листья), доведите до кипения. Разлейте по банкам и закатайте.</li></ol><blockquote><p><strong>Совет:</strong> Оставшиеся пропитанные сиропом листья не выбрасывайте — их можно использовать для заваривания чая. Если хотите ярко-зелёный цвет, добавьте пищевой краситель, но натуральное варенье тоже очень вкусное.</p></blockquote><h2 id="другие-рецепты-с-зеленью" tabindex="-1">Другие рецепты с зеленью: <a class="header-anchor" href="#другие-рецепты-с-зеленью" aria-label="Permalink to &quot;Другие рецепты с зеленью:&quot;">​</a></h2><ul><li><a href="/recipes/basil.html">Базилик</a></li><li><a href="/recipes/microgreens.html">Микрозелень</a></li></ul>',26)])])}const _=i(s,[["render",n]]);export{q as __pageData,_ as default};
